using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using Xunit;
using Moq;
using Microsoft.Extensions.Logging;
using PitWall.WebSocket;
using PitWall.Models;

namespace PitWall.Tests.Stress
{
    /// <summary>\n    /// Stress testing suite for Phase 1 Week 7-8 release validation.\n    /// Tests resilience to network failures, high load, and edge cases.\n    /// </summary>\n    public class StressTests\n    {\n        private Mock<ILogger<WebSocketServer>> _mockLogger;\n        private const int StressTestPort = 9993;\n\n        public StressTests()\n        {\n            _mockLogger = new Mock<ILogger<WebSocketServer>>();\n        }\n\n        [Fact]\n        public async Task HighLoad_1000Broadcasts_NoFailures()\n        {\n            // Stress: 1000 rapid broadcasts\n            // Target: All complete successfully, no exceptions\n            // Arrange\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource();\n            var snapshot = CreateTestTelemetrySnapshot();\n            var failures = new List<Exception>();\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                // Act\n                var tasks = new List<Task>();\n                for (int i = 0; i < 1000; i++)\n                {\n                    tasks.Add(server.BroadcastTelemetryAsync(snapshot, CancellationToken.None)\n                        .ContinueWith(t =>\n                        {\n                            if (t.IsFaulted)\n                                failures.Add(t.Exception!);\n                        }));\n                }\n\n                await Task.WhenAll(tasks);\n\n                // Assert\n                Assert.Empty(failures);\n                Assert.True(server.IsRunning, \"Server should still be running after 1000 broadcasts\");\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task ConcurrentLoad_100Simultaneous_AllComplete()\n        {\n            // Stress: 100 concurrent broadcast operations\n            // Target: All complete within reasonable time, no deadlocks\n            // Arrange\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource();\n            var snapshot = CreateTestTelemetrySnapshot();\n            var sw = Stopwatch.StartNew();\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                // Act\n                var tasks = new Task[100];\n                for (int i = 0; i < 100; i++)\n                {\n                    tasks[i] = server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n                }\n\n                await Task.WhenAll(tasks);\n                sw.Stop();\n\n                // Assert\n                Assert.True(sw.ElapsedMilliseconds < 5000, \n                    $\"100 concurrent broadcasts took {sw.ElapsedMilliseconds}ms, should be <5s\");\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task HighFrequency_100Hz_SustainedFor10Seconds()\n        {\n            // Stress: Sustained 100 packets per second (simulating F1/ACC)  \n            // Target: 10 seconds continuous, no performance degradation\n            // Arrange\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource(TimeSpan.FromSeconds(10));\n            var snapshot = CreateTestTelemetrySnapshot();\n            var broadcastCount = 0;\n            var failures = 0;\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                // Act\n                while (!cts.Token.IsCancellationRequested)\n                {\n                    try\n                    {\n                        await server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n                        broadcastCount++;\n                        await Task.Delay(10); // 10ms interval = 100 Hz\n                    }\n                    catch\n                    {\n                        failures++;\n                    }\n                }\n            }\n            catch (OperationCanceledException)\n            {\n                // Expected\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n\n            // Assert\n            Assert.True(broadcastCount > 90, $\"Expected ~100 broadcasts in 10s, got {broadcastCount}\");\n            Assert.Equal(0, failures);\n        }\n\n        [Fact]\n        public async Task Cancellation_RapidCancel_ServerShutsDownGracefully()\n        {\n            // Stress: Rapid cancellation during broadcasts\n            // Target: Clean shutdown, no hanging resources\n            // Arrange\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource();\n            var snapshot = CreateTestTelemetrySnapshot();\n            var broadcastTasks = new List<Task>();\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                // Act - Start many broadcasts\n                for (int i = 0; i < 50; i++)\n                {\n                    broadcastTasks.Add(server.BroadcastTelemetryAsync(snapshot, CancellationToken.None));\n                }\n\n                // Cancel immediately\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n\n                // Assert\n                Assert.False(server.IsRunning);\n            }\n            finally\n            {\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task SkewedLoad_BurstyTraffic_Handles()\n        {\n            // Stress: Bursty traffic pattern (0 → 100 broadcasts/sec → 0)\n            // Target: Graceful handling of traffic spikes\n            // Arrange\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource();\n            var snapshot = CreateTestTelemetrySnapshot();\n            var totalBroadcasts = 0;\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                // Act - Normal load\n                for (int i = 0; i < 10; i++)\n                {\n                    await server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n                    totalBroadcasts++;\n                }\n\n                // Spike load\n                var spikeTasks = new Task[100];\n                for (int i = 0; i < 100; i++)\n                {\n                    spikeTasks[i] = server.BroadcastTelemetryAsync(snapshot, CancellationToken.None)\n                        .ContinueWith(_ => Interlocked.Increment(ref totalBroadcasts));\n                }\n                await Task.WhenAll(spikeTasks);\n\n                // Back to normal\n                for (int i = 0; i < 10; i++)\n                {\n                    await server.BroadcastTelemetryAsync(snapshot, CancellationToken.None);\n                    totalBroadcasts++;\n                }\n\n                // Assert\n                Assert.True(totalBroadcasts >= 110); // 10 + 100 + 10\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task RecoveryFromFailure_ServerRestart_ResetsState()\n        {\n            // Stress: Server restart clears all state\n            // Target: Clean state after restart\n            // Arrange & Act & Assert - First run\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource();\n            var snapshot = CreateTestTelemetrySnapshot();\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n                \n                var stats1 = server.GetServerStatistics();\n                Assert.Equal(0, stats1.ConnectedClients);\n\n                // Stop server\n                await server.StopAsync(CancellationToken.None);\n                Assert.False(server.IsRunning);\n\n                // Restart\n                cts = new CancellationTokenSource();\n                server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                var stats2 = server.GetServerStatistics();\n                Assert.Equal(0, stats2.ConnectedClients);\n                Assert.Equal(0, stats2.TotalMessages);\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n        }\n\n        [Fact]\n        public async Task Saturation_MaxBroadcastSize_Handled()\n        {\n            // Stress: Large telemetry payloads (worst case)\n            // Target: Process large payloads without errors\n            // Arrange\n            var server = new WebSocketServer(_mockLogger.Object, StressTestPort);\n            var cts = new CancellationTokenSource();\n            var largeSnapshot = CreateLargeTestTelemetrySnapshot();\n            var failures = 0;\n\n            try\n            {\n                await server.StartAsync(cts.Token);\n                await Task.Delay(100);\n\n                // Act - Send large payloads\n                for (int i = 0; i < 100; i++)\n                {\n                    try\n                    {\n                        await server.BroadcastTelemetryAsync(largeSnapshot, CancellationToken.None);\n                    }\n                    catch\n                    {\n                        failures++;\n                    }\n                }\n\n                // Assert\n                Assert.Equal(0, failures);\n            }\n            finally\n            {\n                cts.Cancel();\n                await server.StopAsync(CancellationToken.None);\n                server.Dispose();\n            }\n        }\n\n        private static TelemetrySnapshot CreateTestTelemetrySnapshot()\n        {\n            return new TelemetrySnapshot\n            {\n                Timestamp = DateTime.UtcNow,\n                SessionId = Guid.NewGuid().ToString(),\n                VehicleData = new VehicleData\n                {\n                    Speed = 150.5f,\n                    Throttle = 0.85f,\n                    Brake = 0.0f,\n                    Clutch = 0.0f,\n                    Gear = 4,\n                    EngineRpm = 7500,\n                    FuelRemaining = 45.5f,\n                    SteeringAngle = 0.15f,\n                    InvalidFlagBits = 0\n                },\n                TireData = new TireInfo[4]\n                {\n                    new TireInfo { Temperature = 95.5f, Pressure_Kpa = 220.0f, Wear = 0.15f },\n                    new TireInfo { Temperature = 94.2f, Pressure_Kpa = 218.0f, Wear = 0.14f },\n                    new TireInfo { Temperature = 92.8f, Pressure_Kpa = 215.0f, Wear = 0.16f },\n                    new TireInfo { Temperature = 93.5f, Pressure_Kpa = 217.0f, Wear = 0.15f }\n                },\n                PerformanceData = new PerformanceData\n                {\n                    LateralAccelerationG = 1.2f,\n                    LongitudinalAccelerationG = 0.8f,\n                    VerticalAccelerationG = 0.1f,\n                    LapNumber = 5,\n                    LapTime_Seconds = 95.234f\n                },\n                EnvironmentData = new EnvironmentData\n                {\n                    AirTemperature = 22.5f,\n                    RoadTemperature = 25.0f,\n                    RollAngle = 0.05f,\n                    PitchAngle = -0.02f,\n                    YawAngle = 0.15f\n                }\n            };\n        }\n\n        private static TelemetrySnapshot CreateLargeTestTelemetrySnapshot()\n        {\n            // Create snapshot with maximum possible data (worst case)\n            var snapshot = CreateTestTelemetrySnapshot();\n            snapshot.SessionId = new string('A', 500); // Large session ID\n            return snapshot;\n        }\n    }\n}\n